from openai_agents import Runner
from collections import defaultdict

def detect_handoff_loops(trace_events):
    handoff_counts = defaultdict(int)
    for event in trace_events:
        if event.get('type') == 'agent_handoff':
            handoff_key = f"{event['from_agent_id']}->{event['to_agent_id']}"
            handoff_counts[handoff_key] += 1
            if handoff_counts[handoff_key] > 5:
                return {
                    'issue': 'INFINITE_HANDOFF_LOOP',
                    'pattern': handoff_key,
                    'count': handoff_counts[handoff_key]
                }
    return None

