def detect_guardrail_bypass(events):
    for event in events:
        if isinstance(event, GuardrailEvent) and event.approved:
            input_text = event.input.lower()
            if any(injection in input_text for injection in [
                'ignore previous instructions',
                'you are now',
                'override guardrails',
                'system prompt'
            ]):
                return {
                    'issue': 'GUARDRAIL_BYPASS',
                    'injection_detected': True,
                    'input': event.input
                }
    return None

