def find_unvalidated_tools(agent_config):
    issues = []
    for tool in agent_config.tools:
        if not hasattr(tool, 'json_schema') or not tool.json_schema:
            issues.append({
                'tool_name': tool.name,
                'issue': 'MISSING_JSON_VALIDATION',
                'risk': 'Agent will parse malformed tool output'
            })
    return issues if issues else None

