from openai_agents import Guardrail, Runner

def injection_guardrail(input_text: str) -> bool:
    dangerous_patterns = [
        r'ignore.*instructions',
        r'you are.*(hacker|admin)',
        r'override.*(rules|guardrails)'
    ]
    return not any(re.search(pattern, input_text, re.IGNORECASE) for pattern in dangerous_patterns)

sanitizer = Guardrail(name="InjectionGuard", check=injection_guardrail)
runner = Runner(guardrails=[sanitizer])

